import React, { useEffect, useState } from 'react';
import {
  Container, Typography, Box, Button, TextField, Select, MenuItem, InputLabel, FormControl, Card, CardContent, CardActions, IconButton, Grid, Checkbox
} from '@mui/material';
import FavoriteIcon from '@mui/icons-material/Favorite';
import DeleteIcon from '@mui/icons-material/Delete';
import axios from 'axios';

const CUISINES = ['Indian', 'Chinese', 'Italian', 'Mexican', 'Continental', 'Other'];
const API_URL = 'http://localhost:4000/recipes';

function RecipeForm({ onSave, editing, onCancel }) {
  const [form, setForm] = useState(editing || {
    name: '', ingredients: '', steps: '', cookingTime: '', cuisine: 'Indian', isFavorite: false
  });

  useEffect(() => { if (editing) setForm(editing); }, [editing]);

  const handleChange = e => {
    const { name, value, type, checked } = e.target;
    setForm(f => ({ ...f, [name]: type === 'checkbox' ? checked : value }));
  };

  const handleSubmit = e => {
    e.preventDefault();
    onSave(form);
    if (!editing) setForm({ name: '', ingredients: '', steps: '', cookingTime: '', cuisine: 'Indian', isFavorite: false });
  };

  return (
    <Box component="form" onSubmit={handleSubmit} sx={{ mb: 3 }}>
      <Grid container spacing={2}>
        <Grid item xs={12} sm={6}>
          <TextField label="Name" name="name" value={form.name} onChange={handleChange} fullWidth required />
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl fullWidth>
            <InputLabel>Cuisine</InputLabel>
            <Select name="cuisine" value={form.cuisine} label="Cuisine" onChange={handleChange}>
              {CUISINES.map(c => <MenuItem key={c} value={c}>{c}</MenuItem>)}
            </Select>
          </FormControl>
        </Grid>
        <Grid item xs={12} sm={6}>
          <TextField label="Cooking Time (min)" name="cookingTime" value={form.cookingTime} onChange={handleChange} type="number" fullWidth required />
        </Grid>
        <Grid item xs={12} sm={6}>
          <FormControl>
            <Checkbox name="isFavorite" checked={form.isFavorite} onChange={handleChange} /> Favorite
          </FormControl>
        </Grid>
        <Grid item xs={12}>
          <TextField label="Ingredients" name="ingredients" value={form.ingredients} onChange={handleChange} fullWidth required multiline minRows={2} />
        </Grid>
        <Grid item xs={12}>
          <TextField label="Steps" name="steps" value={form.steps} onChange={handleChange} fullWidth required multiline minRows={2} />
        </Grid>
        <Grid item xs={12}>
          <Button type="submit" variant="contained">{editing ? 'Update' : 'Add'} Recipe</Button>
          {editing && <Button onClick={onCancel} sx={{ ml: 2 }}>Cancel</Button>}
        </Grid>
      </Grid>
    </Box>
  );
}

function RecipeCard({ recipe, onEdit, onDelete, onToggleFavorite }) {
  return (
    <Card sx={{ mb: 2, background: recipe.isFavorite ? '#fffbe6' : 'white' }}>
      <CardContent>
        <Typography variant="h6">{recipe.name}</Typography>
        <Typography variant="body2" color="text.secondary">Cuisine: {recipe.cuisine} | Cooking Time: {recipe.cookingTime} min</Typography>
        <Typography variant="body2"><b>Ingredients:</b> {recipe.ingredients}</Typography>
        <Typography variant="body2"><b>Steps:</b> {recipe.steps}</Typography>
      </CardContent>
      <CardActions>
        <IconButton onClick={() => onToggleFavorite(recipe)} color={recipe.isFavorite ? 'error' : 'default'}>
          <FavoriteIcon />
        </IconButton>
        <Button onClick={() => onEdit(recipe)}>Edit</Button>
        <IconButton onClick={() => onDelete(recipe.id)} color="error">
          <DeleteIcon />
        </IconButton>
      </CardActions>
    </Card>
  );
}

export default function App() {
  const [recipes, setRecipes] = useState([]);
  const [filter, setFilter] = useState({ cuisine: '', search: '', favorite: false });
  const [editing, setEditing] = useState(null);

  const fetchRecipes = async () => {
    const params = {};
    if (filter.cuisine) params.cuisine = filter.cuisine;
    if (filter.search) params.search = filter.search;
    if (filter.favorite) params.favorite = true;
    const res = await axios.get(API_URL, { params });
    setRecipes(res.data);
  };

  useEffect(() => { fetchRecipes(); }, [filter]);

  const handleSave = async (data) => {
    if (editing) {
      await axios.put(`${API_URL}/${editing.id}`, data);
      setEditing(null);
    } else {
      await axios.post(API_URL, data);
    }
    fetchRecipes();
  };

  const handleDelete = async (id) => {
    await axios.delete(`${API_URL}/${id}`);
    fetchRecipes();
  };

  const handleToggleFavorite = async (recipe) => {
    await axios.patch(`${API_URL}/${recipe.id}/favorite`, { isFavorite: !recipe.isFavorite });
    fetchRecipes();
  };

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Typography variant="h4" align="center" gutterBottom>RecipeBox</Typography>
      <Box sx={{ mb: 3 }}>
        <RecipeForm onSave={handleSave} editing={editing} onCancel={() => setEditing(null)} />
      </Box>
      <Box sx={{ mb: 2, display: 'flex', gap: 2, flexWrap: 'wrap' }}>
        <FormControl sx={{ minWidth: 140 }}>
          <InputLabel>Cuisine</InputLabel>
          <Select value={filter.cuisine} label="Cuisine" onChange={e => setFilter(f => ({ ...f, cuisine: e.target.value }))}>
            <MenuItem value="">All</MenuItem>
            {CUISINES.map(c => <MenuItem key={c} value={c}>{c}</MenuItem>)}
          </Select>
        </FormControl>
        <TextField label="Search by name or ingredient" value={filter.search} onChange={e => setFilter(f => ({ ...f, search: e.target.value }))} />
        <FormControl>
          <Checkbox checked={filter.favorite} onChange={e => setFilter(f => ({ ...f, favorite: e.target.checked }))} /> Favorites
        </FormControl>
      </Box>
      <Box>
        {recipes.length === 0 ? (
          <Typography>No recipes found.</Typography>
        ) : (
          recipes.map(recipe => (
            <RecipeCard
              key={recipe.id}
              recipe={recipe}
              onEdit={setEditing}
              onDelete={handleDelete}
              onToggleFavorite={handleToggleFavorite}
            />
          ))
        )}
      </Box>
    </Container>
  );
}
